package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsNull() {
        CSVFormat formatWithNullComment = csvFormat.withCommentMarker((Character) null);
        assertFalse(formatWithNullComment.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsSet() {
        CSVFormat formatWithComment = csvFormat.withCommentMarker('#');
        assertTrue(formatWithComment.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_onNewInstanceWithCommentMarker() {
        CSVFormat formatWithComment = csvFormat.withCommentMarker('#');
        assertTrue(formatWithComment.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_onNewInstanceWithoutCommentMarker() {
        CSVFormat formatWithoutComment = csvFormat.withCommentMarker((Character) null);
        assertFalse(formatWithoutComment.isCommentMarkerSet());
    }
}
